import pytest
import requests

BASE_URL = "<BASE_URL>"

@pytest.fixture
def auth_headers():
    return <auth_headers_fixture>

@pytest.fixture
def registered_biller():
    return <registered_biller_fixture>

def test_billpay_valid_mid_range_amount_returns_scheduled(auth_headers, registered_biller):
    payload = {
        "biller_id": registered_biller["id"],
        "account_id": "<ACCOUNT_ID>",
        "amount": 500.00,
        "currency": "USD"
    }
    resp = requests.post(f"{BASE_URL}/billpay", json=payload, headers=auth_headers)
    assert resp.status_code == 201
    body = resp.json()
    assert body["status"] == "scheduled"
    assert body.get("settlement_date") is not None

